// WOA 悬浮注入 — 在 WPS协作 DevTools 控制台粘贴运行
// 再次运行可关闭
(function(){var id='cc-float-frame';var f=document.getElementById(id);if(f){f.remove();return;}f=document.createElement('iframe');f.id=id;f.src='http://localhost:5174/panel?mode=float';f.allow='clipboard-write';f.style.cssText='position:fixed;right:0;bottom:0;width:480px;height:640px;border:none;z-index:99999;background:transparent;pointer-events:none;';f.setAttribute('allowtransparency','true');document.body.appendChild(f);f.onload=function(){try{f.contentDocument.body.style.background='transparent';f.contentDocument.documentElement.style.background='transparent';}catch(e){}};var ob=new MutationObserver(function(){try{var p=f.contentDocument?.querySelector('.cc-panel');f.style.pointerEvents=(p&&p.classList.contains('cc-visible'))?'auto':'auto';}catch(e){}});try{ob.observe(f.contentDocument.body,{subtree:true,attributes:true,attributeFilter:['class']});}catch(e){f.style.pointerEvents='auto';}})();
